    } else {
        quicksort(arr, 0, arr.len() - 1);
    }
}

fn quicksort<T: Ord + Clone>(arr: &mut [T], low: usize, high: usize) {
    if low < high {
        if high - low < 20 {
            insertion_sort(&mut arr[low..=high]);
            return;
        }
        let pivot_index = partition(arr, low, high);
        if pivot_index > 0 {
            quicksort(arr, low, pivot_index - 1);
        }
        quicksort(arr, pivot_index + 1, high);
    }
}

fn partition<T: Ord + Clone>(arr: &mut [T], low: usize, high: usize) -> usize {
    let m = low + (high - low) / 2;
    if arr[m] < arr[low] { arr.swap(low, m); }
    if arr[high] < arr[low] { arr.swap(low, high); }
    if arr[high] < arr[m] { arr.swap(m, high); }
    arr.swap(m, high);

    let (mut i, pivot) = (low, arr[high].clone());
    for j in low..high {
        if arr[j] <= pivot {
            arr.swap(i, j);
            i += 1;
        }
    }
    arr.swap(i, high);
    i
}

fn insertion_sort<T: Ord>(arr: &mut [T]) {
    for i in 1..arr.len() {
        let mut j = i;
        while j > 0 && arr[j - 1] > arr[j] {
            arr.swap(j, j - 1);
            j -= 1;
        }
    }
}
